import dspy
import re

def metric(gold, pred, trace=None, pred_name=None, pred_trace=None):
    """Score a QA prediction against ground truth answer."""

    # --- Extract gold answer ---
    try:
        gold_answer = getattr(gold, "answer", None) or gold.get("answer") if isinstance(gold, dict) else None
        if gold_answer is None:
            return dspy.Prediction(score=0.0, feedback="Parse error: gold has no 'answer' field")
    except Exception:
        return dspy.Prediction(score=0.0, feedback=f"Parse error: could not extract gold.answer from {gold!r}")

    # --- Extract predicted answer ---
    try:
        pred_answer = getattr(pred, "answer", None)
        if pred_answer is None and isinstance(pred, dict):
            pred_answer = pred.get("answer")
        if pred_answer is None:
            return dspy.Prediction(score=0.0, feedback="Parse error: prediction has no 'answer' field")
    except Exception:
        return dspy.Prediction(score=0.0, feedback=f"Parse error: could not extract pred.answer from {pred!r}")

    # --- Normalize for comparison ---
    def normalize(s):
        s = str(s).strip().lower()
        # Strip trailing punctuation
        s = s.rstrip(".")
        # Collapse multiple spaces
        s = re.sub(r"\s+", " ", s)
        return s

    norm_gold = normalize(gold_answer)
    norm_pred = normalize(pred_answer)

    # --- Compare ---
    if norm_gold == norm_pred:
        return dspy.Prediction(
            score=1.0,
            feedback=f"Correct — answer = {gold_answer!r} matches (case-insensitive, stripped)."
        )
    else:
        # Partial match: check if one contains the other (e.g., "Mount Everest" vs "Everest")
        if norm_gold in norm_pred or norm_pred in norm_gold:
            return dspy.Prediction(
                score=0.8,
                feedback=f"Partial — answer got {pred_answer!r}, expected {gold_answer!r}. "
                         f"Prediction is a substring/superset of the correct answer. "
                         f"Return the exact answer without extra words or punctuation."
            )
        # Check for common variations
        # Remove common prefixes/suffixes and compare
        variations = [
            lambda s: re.sub(r"^(the| Mount| Mount | Mt\.? )", "", s, flags=re.IGNORECASE),
        ]
        for var_fn in variations:
            if var_fn(norm_pred) == var_fn(norm_gold):
                return dspy.Prediction(
                    score=0.7,
                    feedback=f"Incorrect: answer got {pred_answer!r}, expected {gold_answer!r}. "
                             f"Found matching after stripping common prefixes. "
                             f"Return the canonical name exactly as given in the question."
                )

        return dspy.Prediction(
            score=0.0,
            feedback=f"Incorrect: answer got {pred_answer!r}, expected {gold_answer!r}. "
                     f"Strings differ after normalization. Check spelling, articles (the/a), "
                     f"and abbreviations. Return the exact proper noun from the knowledge base."
        )

